sys_script_email.script:
(function runMailScript( current,  template, email, email_action, event) {

	//HT - STRY0033444 
	//this email script is used with the scheduled job for acceptance overdue tasks and the acceptance overdue email notification

	//parse JSON data and format HTML for the email notification, we had to use this email script in order to send multi value data through an event
	var obj = JSON.parse(event.parm1);

	var task_link = 'discovertaskerportal?sys_id='+ obj.id +'&view=sp&id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance';

	template.print("<p><span style='font-family: georgia, palatino; font-size: 12pt;'><a href='"+ task_link +"'>"+obj.pending_task+"</a>, was assigned to " +obj.assigned_user+ " and has not been accepted. </span></p>");
	template.print("<p><span style='font-family: georgia, palatino; font-size: 12pt;'>The suspense date is "+obj.suspense_date+" </span></p>");

})(current,  template, email, email_action, event);
